object Solution {

  // Helper function to check if a path exists using at most k heavy edges for a given threshold T
  def canReach(n: Int, adj: Array[MutableList[(Int, Long)]], source: Int, target: Int, k: Int, threshold: Long): Boolean = {
    if (source == target) return true

    // Dijkstra's algorithm: finding minimum heavy edge count
    // D[i] stores the minimum number of heavy edges needed to reach node i
    val infinity = k + 1 // Since max heavy edges needed is at most k+1 if no path exists within k
    val dist = Array.fill[Int](n) { infinity }
    dist(source) = 0

    // PriorityQueue stores (heavy_count, node)
    // We use a mutable structure mimicking a min-heap for (heavy_count, node)
    // Since standard Scala doesn't provide a PQ easily, we use Java's PriorityQueue for efficiency
    import java.util.PriorityQueue

    // PQ stores (heavy_count, node)
    val pq = new PriorityQueue[Tuple2[Int, Int]]()
    pq.add(Tuple2(0, source))

    while (!pq.isEmpty) {
      val (d, u) = pq.poll()

      if (d > dist(u)) continue

      if (u == target) {
        // Optimization: if we reached the target, we found the minimum heavy count
        return d <= k
      }

      for ((v, w) <- adj(u)) {
        // Cost of edge (u, v): 1 if heavy (w > T), 0 if light (w <= T)
        val cost = if (w > threshold) 1 else 0

        val newDist = d + cost

        if (newDist <= k && newDist < dist(v)) {
          dist(v) = newDist
          pq.add(Tuple2(newDist, v))
        }
      }
    }

    // After Dijkstra, check the target distance
    dist(target) <= k
  }

