    val adj = Array.fill(n)(mutable.ListBuffer[(Int, Long)]())
    val uniqueWeights = mutable.HashSet[Long]()

    for (edge <- edges_long) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val w = edge(2)

      adj(u).append((v, w))
      adj(v).append((u, w))
      uniqueWeights.add(w)
