        this.heap.push([priority, value]);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return min;
    }
}


/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // 1. Build Adjacency List
    // Adj[u] stores list of [v, weight]
    const adj = Array(n).fill(0).map(() => []);
    let maxWeight = 0;

    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
        if (w > maxWeight) {
            maxWeight = w;
        }
    }

    /**
     * Checks if there exists a path from source to target using at most k heavy edges 
     * given a specific threshold.
     * @param {number} threshold
     * @returns {boolean}
     */
    const check = (threshold) => {
        // Dijkstra's algorithm to find minimum heavy edges required
        // dist[u] = minimum count of heavy edges to reach u
        const dist = Array(n).fill(Infinity);
        dist[source] = 0;

        // PQ stores [heavy_edge_count, node]
        const pq = new MinPriorityQueue();
        pq.enqueue(0, source);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            if (u === target) {
                // Optimization: if we reached target, check if the count is <= k
                return d <= k;
            }

            for (const [v, weight] of adj[u]) {
                // Cost is 1 if heavy (weight > threshold), 0 if light
                const cost = weight > threshold ? 1 : 0;

                const newDist = d + cost;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.enqueue(newDist, v);
                }
            }
        }

        // If target was never reached, or the minimum heavy count exceeds k
        return dist[target] <= k;
    };

    // 2. Binary Search on the threshold

    // Search space: [L, R]
    // L=0 is the minimum possible threshold.
    // R=maxWeight + 1 ensures all edges are light (threshold >= maxWeight).
    let L = 0;
    let R = maxWeight + 1; 
    let minThreshold = -1;

    while (L <= R) {
        // Use Math.floor for integer division
        const M = Math.floor((L + R) / 2); 

        if (check(M)) {
            // Threshold M works. This is a potential answer. Try smaller.
            minThreshold = M;
            R = M - 1;
        } else {
            // Threshold M is too strict (too small). Need a larger threshold.
            L = M + 1;
        }
    }

    return minThreshold;
}
